  '[{"label": "مقرر منزلتا الرضا والشكر — مسار التربية", "url": "/learning/paths/tarbiyah"}, {"label": "مقرر الفضائل المنجية — مسار التربية", "url": "/learning/paths/tarbiyah"}, {"label": "مقرر آفات النفس — مسار التربية", "url": "/learning/paths/tarbiyah"}, {"label": "مدارج السالكين — المكتبة", "url": "/library/book-madarij"}, {"label": "إحياء علوم الدين — المكتبة", "url": "/library/book-ihya"}]'::jsonb,
  '[{"question": "ما الفرق بين الصبر والرضا؟", "answer": "الصبر حبس النفس عن التسخط عند المكروه مع بقاء ألم وجده في النفس، أما الرضا فأعلى منه: طمأنينة القلب التامة بقضاء الله دون منازعة داخلية، ويشمل السراء والضراء معاً لا الضراء فقط."}, {"question": "هل حديث الحسد الوارد في المقال صحيح؟", "answer": "رواه أبو داود عن أبي هريرة رضي الله عنه؛ لم يتيسَّر تحقُّق درجة تصحيح قاطعة له من مصدر مباشر متاح، فنُقل بمصدره دون ادّعاء تصحيح لم يُتحقَّق منه — بأمانة علمية."}, {"question": "لماذا قُرن الحسد والكِبر تحديداً بمنازل الصبر والشكر والرضا؟", "answer": "لأن الحسد يتنافى مع الرضا بقسمة الله ومع شكر نعمة النفس، والكِبر يتضمَّن رفض القضاء الذي وضع صاحبه في منزلته — فكلاهما يهدم هذه المنازل الثلاث من الداخل بدل بنائها."}]'::jsonb,
